vector<string> uncommonFromSentences(string s1, string s2) {
    unordered_map<string, int> count;
    string s = s1 + " " + s2;
    vector<string> res;
    for (string word : split(s, ' ')) {
        count[word]++;
    }
    for (string word : split(s1, ' ')) {
        if (count[word] == 1) res.push_back(word);
    }
    for (string word : split(s2, ' ')) {
        if (count[word] == 1) res.push_back(word);
    }
    return res;
}

vector<string> split(string s, char c) {
    vector<string> res;
    string t = "";
    for (char ch : s) {
        if (ch == c) {
            res.push_back(t);
            t = "";
        } else {
            t += ch;
        }
    }
    res.push_back(t);
    return res;
}
